import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import signupBg from '../assets/images/loginbg.png';

const Signup = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  
  const { signup, isAuthenticated } = useAuth();
  const navigate = useNavigate();

  // Redirect if already authenticated
  React.useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard');
    }
  }, [isAuthenticated, navigate]);

  const validateEmail = (email) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  };

  const validatePhone = (phone) => {
    const re = /^\+?[0-9\s\-]{7,15}$/;
    return re.test(phone);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    // Validation
    if (name.trim().length < 3) {
      setError('Please enter at least 3 characters for full name');
      return;
    }

    if (!validateEmail(email.trim())) {
      setError('Please enter a valid email address');
      return;
    }

    if (!validatePhone(phone.trim())) {
      setError('Please enter a valid phone number');
      return;
    }

    if (username.trim().length < 3) {
      setError('Username must be at least 3 characters');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters');
      return;
    }

    setLoading(true);

    try {
      const result = await signup(name, email, password);
      
      if (result.success) {
        navigate('/dashboard');
      } else {
        setError(result.error || 'Signup failed. Please try again.');
      }
    } catch (err) {
      setError('An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{...styles.pageWrapper, backgroundImage: `url(${signupBg})`}}>
      <div style={styles.signupContainer}>
        <form id="signupForm" onSubmit={handleSubmit} novalidate style={styles.form}>
          {/* Logo Section - Matching Login Page Style */}
          <div style={styles.logoContainer}>
            <img
              src="https://img.icons8.com/ios-filled/50/0000FF/car.png"
              alt=""
              style={styles.logoIcon}
              aria-hidden="true"
              draggable="false"
            />
            <div>
              <div style={styles.logoTextMain}>Rent a Car</div>
              <div style={styles.logoTextSub}>Management System</div>
            </div>
          </div>

          <h2 style={styles.heading}>Create an account</h2>
          <p style={styles.subtitle}>Sign up to get started</p>

          {/* Error Message */}
          {error && (
            <div style={styles.errorMessage}>
              {error}
            </div>
          )}

          {/* Full Name Field */}
          <label htmlFor="fullname" style={styles.label}>
            <span style={styles.icon}>&#128100;</span>
            <input
              type="text"
              id="fullname"
              name="fullname"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Full Name"
              autoComplete="name"
              required
              style={styles.input}
              disabled={loading}
            />
          </label>

          {/* Email Field */}
          <label htmlFor="email" style={styles.label}>
            <span style={styles.icon}>&#9993;</span>
            <input
              type="email"
              id="email"
              name="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Email address"
              autoComplete="email"
              required
              style={styles.input}
              disabled={loading}
            />
          </label>

          {/* Phone Field */}
          <label htmlFor="phone" style={styles.label}>
            <span style={styles.icon}>&#128222;</span>
            <input
              type="tel"
              id="phone"
              name="phone"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              placeholder="Phone Number"
              autoComplete="tel"
              required
              pattern="^\+?[0-9\s\-]{7,15}$"
              style={styles.input}
              disabled={loading}
            />
          </label>

          {/* Username Field */}
          <label htmlFor="username" style={styles.label}>
            <span style={styles.icon}>&#128100;</span>
            <input
              type="text"
              id="username"
              name="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Username"
              autoComplete="username"
              required
              minLength="3"
              style={styles.input}
              disabled={loading}
            />
          </label>

          {/* Password Field */}
          <label htmlFor="password" style={styles.label}>
            <span style={styles.icon}>&#128274;</span>
            <input
              type="password"
              id="password"
              name="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Password"
              autoComplete="new-password"
              required
              minLength="6"
              style={styles.input}
              disabled={loading}
            />
          </label>

          {/* Submit Button */}
          <button 
            type="submit" 
            style={styles.signupBtn}
            disabled={loading}
          >
            {loading ? 'Creating Account...' : 'Sign Up'}
          </button>
        </form>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cantata+One&display=swap');
        
        input:focus {
          border-color: #3030cc !important;
          outline: none;
        }
        
        button:hover:not(:disabled) {
          background-color: #1f1f8a !important;
        }
      `}</style>
    </div>
  );
};

const styles = {
  pageWrapper: {
    minHeight: '100vh',
    margin: 0,
    fontFamily: "'Cantata One', serif",
    backgroundRepeat: 'no-repeat',
    backgroundPosition: 'center center',
    backgroundSize: 'cover',
    backgroundAttachment: 'fixed',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    padding: '20px',
  },
  signupContainer: {
    background: 'white',
    padding: '30px 35px 40px 35px',
    width: '320px',
    boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
    borderRadius: '6px',
    textAlign: 'center',
  },
  form: {
    display: 'block',
  },
  logoContainer: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: '20px',
    gap: '10px',
  },
  logoIcon: {
    width: '36px',
    height: '36px',
    filter: 'drop-shadow(0 1px 0 rgba(0,0,0,0.1))',
  },
  logoTextMain: {
    fontWeight: '600',
    fontSize: '18px',
    color: '#000',
    userSelect: 'none',
  },
  logoTextSub: {
    fontSize: '11px',
    color: '#555',
    lineHeight: '1.1',
    userSelect: 'none',
  },
  heading: {
    margin: '0 0 6px 0',
    fontWeight: '600',
    fontSize: '20px',
    color: '#000',
    userSelect: 'none',
  },
  subtitle: {
    margin: '0 0 20px 0',
    fontSize: '13px',
    color: '#555',
    userSelect: 'none',
  },
  label: {
    position: 'relative',
    display: 'block',
    marginBottom: '12px',
  },
  icon: {
    position: 'absolute',
    top: '50%',
    left: '12px',
    transform: 'translateY(-50%)',
    color: '#777',
    fontSize: '16px',
    pointerEvents: 'none',
    userSelect: 'none',
  },
  input: {
    width: '100%',
    padding: '10px 12px 10px 36px',
    fontSize: '14px',
    border: '1.5px solid #ccc',
    borderRadius: '6px',
    transition: 'border-color 0.3s ease',
    outlineOffset: '2px',
    boxSizing: 'border-box',
  },
  signupBtn: {
    width: '100%',
    backgroundColor: '#3030cc',
    color: 'white',
    fontWeight: '600',
    padding: '12px 0',
    border: 'none',
    borderRadius: '8px',
    fontSize: '15px',
    cursor: 'pointer',
    transition: 'background-color 0.3s ease',
    userSelect: 'none',
  },
  errorMessage: {
    fontSize: '11px',
    color: '#e74c3c',
    height: '14px',
    margin: '4px 0 8px 0',
    textAlign: 'left',
    userSelect: 'none',
  },
};

export default Signup;
